QueryScript.Source:
import sailpoint.object.*;
import sailpoint.tools.Util;

if (value != null) {
QueryOptions auditQO = new QueryOptions();
auditQO.addFilter(Filter.eq("action", "identityLifecycleEvent"));
auditQO.addFilter(Filter.eq("string1", "HR Source Lifecycle Event - Leaver"));       //Replace  HR Source Lifecycle Event - Leaver = LEAVER FEATURE and string1 = string1

Iterator it = context.search(AuditEvent.class, auditQO, "target");
List identityNames = new ArrayList();

while (it.hasNext()) {
Object[] row = (Object[]) it.next();
String target = (String) row[0];

if (target != null && target.startsWith("Identity:")) {
identityNames.add(target.substring(9)); 
}
}
Util.flushIterator(it);

if (!identityNames.isEmpty()) {
log.error("applications input value : "+value);
Filter filter = Filter.and(Filter.eq("identity.department","EngineeringCoach"),Filter.eq("application.id", value),Filter.in("identity.name", identityNames));        //Replace Inventory = ITS  and department = VPU 
queryOptions.addFilter(filter);
} else {
queryOptions.addFilter(Filter.isnull("id"));
}
}

return queryOptions;

